# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for collaborative team work. It provides
user, project, task, messaging, performance-dashboard and reporting features.

The implementation relies only on the Python standard library. Every public
accessor returns deep copies so that callers can never mutate internal state by
holding on to a returned object.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from collections import defaultdict
from dataclasses import dataclass
from datetime import datetime
from enum import Enum
from typing import Callable, List, Optional


# ---------------------------------------------------------------------------
# Enums
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied data fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal stores
# ---------------------------------------------------------------------------
class _BaseStore:
    """A namespaced data container that shares the manager-wide lock."""

    def __init__(self, lock):
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._username_index = {}
        self._email_index = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._by_project = defaultdict(set)
        self._by_assignee = defaultdict(set)


class _MessageStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._by_id = {}
        self._by_project = defaultdict(set)
        self._by_task = defaultdict(set)


class _PerformanceStore(_BaseStore):
    def __init__(self, lock):
        super().__init__(lock)
        self._ratings = {}
        self._by_ratee = defaultdict(list)


class _ReportStore(_BaseStore):
    pass


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates all collaboration features behind a single shared lock."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._next_id = 1

        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- helpers ------------------------------------------------------------
    def _new_id(self):
        nid = self._next_id
        self._next_id += 1
        return nid

    @staticmethod
    def _copy(obj):
        return copy.deepcopy(obj)

    @staticmethod
    def _validate_username(username):
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")
        return username.strip()

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        mail = email.strip()
        if not mail or "@" not in mail:
            raise ValidationError("email must be a valid address")
        return mail

    @staticmethod
    def _validate_name(name, label):
        if not isinstance(name, str) or not name.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return name.strip()

    @staticmethod
    def _validate_date_range(start, end):
        if start is None or end is None:
            raise ValidationError("start and end dates are required")
        if end < start:
            raise ValidationError("end date must not be before start date")

    def _require_user(self, user_id):
        user = self.users._by_id.get(user_id)
        if user is None:
            raise NotFoundError("user not found: {0}".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._by_id.get(project_id)
        if project is None:
            raise NotFoundError("project not found: {0}".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._by_id.get(task_id)
        if task is None:
            raise NotFoundError("task not found: {0}".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._by_id.get(message_id)
        if message is None:
            raise NotFoundError("message not found: {0}".format(message_id))
        return message

    # -- user management ----------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            uname = self._validate_username(username)
            mail = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if uname in self.users._username_index:
                raise DuplicateError("username already exists: {0}".format(uname))
            if mail in self.users._email_index:
                raise DuplicateError("email already exists: {0}".format(mail))
            uid = self._new_id()
            user = User(
                id=uid,
                username=uname,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self.users._by_id[uid] = user
            self.users._username_index[uname] = uid
            self.users._email_index[mail] = uid
            return self._copy(user)

    def get_user(self, user_id):
        with self._lock:
            return self._copy(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return [
                self._copy(self.users._by_id[uid])
                for uid in sorted(self.users._by_id)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)
            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not None:
                new_username = self._validate_username(username)
                if (
                    new_username != user.username
                    and new_username in self.users._username_index
                ):
                    raise DuplicateError(
                        "username already exists: {0}".format(new_username)
                    )
            if email is not None:
                new_email = self._validate_email(email)
                if (
                    new_email != user.email
                    and new_email in self.users._email_index
                ):
                    raise DuplicateError(
                        "email already exists: {0}".format(new_email)
                    )
            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                del self.users._username_index[user.username]
                self.users._username_index[new_username] = user.id
                user.username = new_username
            if new_email != user.email:
                del self.users._email_index[user.email]
                self.users._email_index[new_email] = user.id
                user.email = new_email
            user.role = new_role
            return self._copy(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self._require_user(user_id)
            for project in self.projects._by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")
            for task_id in list(self.tasks._by_assignee.get(user_id, set())):
                task = self.tasks._by_id.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")
            del self.users._by_id[user_id]
            self.users._username_index.pop(user.username, None)
            self.users._email_index.pop(user.email, None)

    # -- project management -------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            pname = self._validate_name(name, "project name")
            self._validate_date_range(start_date, end_date)
            self._require_user(owner_id)
            pid = self._new_id()
            project = Project(
                id=pid,
                name=pname,
                description=description if description else "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._by_id[pid] = project
            return self._copy(project)

    def get_project(self, project_id):
        with self._lock:
            return self._copy(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return [
                self._copy(self.projects._by_id[pid])
                for pid in sorted(self.projects._by_id)
            ]

    def update_project(
        self, project_id, name=None, description=None, start_date=None, end_date=None
    ):
        with self._lock:
            project = self._require_project(project_id)
            new_name = project.name
            if name is not None:
                new_name = self._validate_name(name, "project name")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            self._validate_date_range(new_start, new_end)

            project.name = new_name
            if description is not None:
                project.description = description
            project.start_date = new_start
            project.end_date = new_end
            return self._copy(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            task_ids = list(self.tasks._by_project.get(project_id, set()))
            for tid in task_ids:
                task = self.tasks._by_id.pop(tid, None)
                if task is None:
                    continue
                if task.assignee_id is not None:
                    self.tasks._by_assignee.get(task.assignee_id, set()).discard(tid)
                for mid in list(self.messages._by_task.get(tid, set())):
                    self.messages._by_id.pop(mid, None)
                self.messages._by_task.pop(tid, None)
            self.tasks._by_project.pop(project_id, None)

            for mid in list(self.messages._by_project.get(project_id, set())):
                self.messages._by_id.pop(mid, None)
            self.messages._by_project.pop(project_id, None)

            del self.projects._by_id[project_id]

    # -- task management ----------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            ttitle = self._validate_name(title, "task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not be before project start")
            tid = self._new_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=ttitle,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks._by_id[tid] = task
            self.tasks._by_project[project_id].add(tid)
            if assignee_id is not None:
                self.tasks._by_assignee[assignee_id].add(tid)
            return self._copy(task)

    def get_task(self, task_id):
        with self._lock:
            return self._copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tids = self.tasks._by_project.get(project_id, set())
            return [self._copy(self.tasks._by_id[tid]) for tid in sorted(tids)]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._require_user(assignee_id)
            tids = self.tasks._by_assignee.get(assignee_id, set())
            return [self._copy(self.tasks._by_id[tid]) for tid in sorted(tids)]

    def _set_assignee(self, task_id, assignee_id):
        task = self._require_task(task_id)
        if assignee_id is not None:
            self._require_user(assignee_id)
        if task.assignee_id is not None:
            self.tasks._by_assignee.get(task.assignee_id, set()).discard(task_id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks._by_assignee[assignee_id].add(task_id)
        return task

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            return self._copy(self._set_assignee(task_id, assignee_id))

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            return self._copy(self._set_assignee(task_id, new_assignee_id))

    def unassign_task(self, task_id):
        with self._lock:
            return self._copy(self._set_assignee(task_id, None))

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not be before project start")
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return self._copy(task)

    # -- messaging ----------------------------------------------------------
    def _build_attachments(self, raw_attachments, uploader_id, when):
        attachments = []
        for entry in raw_attachments:
            filename, data = entry
            if not isinstance(filename, str) or not filename:
                raise ValidationError("attachment filename must be non-empty")
            size = len(data) if data is not None else 0
            attachments.append(
                Attachment(
                    filename=filename,
                    size=size,
                    uploaded_by=uploader_id,
                    uploaded_at=when,
                )
            )
        return attachments

    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ):
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            raw_attachments = attachments or []
            has_body = isinstance(body, str) and body.strip() != ""
            if not has_body and not raw_attachments:
                raise ValidationError("message requires a body or attachments")

            now = self._now()
            built = self._build_attachments(raw_attachments, author_id, now)

            if parent_id is not None:
                self._require_message(parent_id)

            mid = self._new_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=body if isinstance(body, str) else "",
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built,
                created_at=now,
                edited_at=None,
            )
            self.messages._by_id[mid] = message
            if project_id is not None:
                self.messages._by_project[project_id].add(mid)
            if task_id is not None:
                self.messages._by_task[task_id].add(mid)
            return self._copy(message)

    def edit_message(self, message_id, editor_id, body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if not isinstance(body, str) or not body.strip():
                raise ValidationError("message body must be non-empty")
            message.body = body
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to this message"
                )
            if not isinstance(filename, str) or not filename:
                raise ValidationError("attachment filename must be non-empty")
            attachment = Attachment(
                filename=filename,
                size=len(data) if data is not None else 0,
                uploaded_by=uploader_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return self._copy(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            mids = self.messages._by_project.get(project_id, set())
            return [self._copy(self.messages._by_id[mid]) for mid in sorted(mids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            mids = self.messages._by_task.get(task_id, set())
            return [self._copy(self.messages._by_id[mid]) for mid in sorted(mids)]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete this message"
                )
            if message.project_id is not None:
                self.messages._by_project.get(message.project_id, set()).discard(
                    message_id
                )
            if message.task_id is not None:
                self.messages._by_task.get(message.task_id, set()).discard(message_id)
            del self.messages._by_id[message_id]

    # -- performance dashboard ---------------------------------------------
    def _assignee_tasks(self, user_id):
        tids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._by_id[tid] for tid in tids if tid in self.tasks._by_id]

    @staticmethod
    def _completion_time_seconds(task):
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            durations = [
                self._completion_time_seconds(t)
                for t in tasks
                if self._completion_time_seconds(t) is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users may not rate themselves")
            if task_id is not None:
                self._require_task(task_id)
            rid = self._new_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback if feedback else "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._ratings[rid] = rating
            self.performance._by_ratee[ratee_id].append(rid)
            return self._copy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            rids = self.performance._by_ratee.get(user_id, [])
            ratings = [self.performance._ratings[rid] for rid in rids]
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [self._copy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._assignee_tasks(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            durations = [
                self._completion_time_seconds(t)
                for t in tasks
                if self._completion_time_seconds(t) is not None
            ]
            avg_time = sum(durations) / len(durations) if durations else None

            rids = self.performance._by_ratee.get(user_id, [])
            ratings = [self.performance._ratings[rid] for rid in rids]
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports ------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tids = self.tasks._by_project.get(project_id, set())
            tasks = [self.tasks._by_id[tid] for tid in tids]
            total = len(tasks)
            now = self._now()

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0

            overdue = 0
            for task in tasks:
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {
                        "total_tasks": 0,
                        "completed_tasks": 0,
                        "in_progress_tasks": 0,
                        "not_started_tasks": 0,
                    },
                )
                bucket["total_tasks"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed_tasks"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    bucket["in_progress_tasks"] += 1
                else:
                    bucket["not_started_tasks"] += 1
            for bucket in per_assignee.values():
                tot = bucket["total_tasks"]
                bucket["completion_rate"] = (
                    bucket["completed_tasks"] / tot if tot else 0.0
                )

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _scoped_tasks(self, project_id=None):
        if project_id is None:
            return list(self.tasks._by_id.values())
        tids = self.tasks._by_project.get(project_id, set())
        return [self.tasks._by_id[tid] for tid in tids]

    def _user_row(self, user_id, tasks):
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        completion_rate = completed / total if total else 0.0
        durations = [
            self._completion_time_seconds(t)
            for t in tasks
            if self._completion_time_seconds(t) is not None
        ]
        avg_time = sum(durations) / len(durations) if durations else None
        rids = self.performance._by_ratee.get(user_id, [])
        ratings = [self.performance._ratings[rid] for rid in rids]
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count if rating_count else 0.0
        )
        user = self.users._by_id.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else "",
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": completion_rate,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
            tasks = self._scoped_tasks(project_id)
            grouped = defaultdict(list)
            for task in tasks:
                if task.assignee_id is not None:
                    grouped[task.assignee_id].append(task)
            rows = [
                self._user_row(uid, grouped[uid]) for uid in sorted(grouped)
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(self._assignee_tasks(user_id), key=lambda t: t.id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            durations = [
                self._completion_time_seconds(t)
                for t in tasks
                if self._completion_time_seconds(t) is not None
            ]
            avg_time = sum(durations) / len(durations) if durations else None
            task_rows = [
                {
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "tasks": task_rows,
            }

    # -- export -------------------------------------------------------------
    def export_report(self, report, fmt):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    @staticmethod
    def _flatten_value(value):
        if isinstance(value, (dict, list)):
            return repr(value)
        if value is None:
            return ""
        return value

    def _report_to_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        rows = report.get("rows")
        if isinstance(rows, list):
            fieldnames = []
            for row in rows:
                for key in row:
                    if key not in fieldnames:
                        fieldnames.append(key)
            if not fieldnames:
                fieldnames = [
                    "user_id",
                    "username",
                    "total_tasks",
                    "completed_tasks",
                    "completion_rate",
                    "average_completion_time",
                    "rating_count",
                    "rating_average",
                ]
            writer.writerow(fieldnames)
            for row in rows:
                writer.writerow(
                    [self._flatten_value(row.get(name, "")) for name in fieldnames]
                )
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._flatten_value(value)])
        return output.getvalue()

    def _report_to_lines(self, report):
        lines = []
        rtype = report.get("report_type", "report")
        lines.append("Report: {0}".format(rtype))
        for key, value in report.items():
            if key == "rows" and isinstance(value, list):
                lines.append("rows:")
                for row in value:
                    lines.append("  " + ", ".join(
                        "{0}={1}".format(k, v) for k, v in row.items()
                    ))
            else:
                lines.append("{0}: {1}".format(key, self._flatten_value(value)))
        return lines

    def _report_to_pdf(self, report):
        lines = self._report_to_lines(report)

        def escape(text):
            return (
                str(text)
                .replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 12 Tf", "72 720 Td", "14 TL"]
        for line in lines:
            content_parts.append("({0}) Tj".format(escape(line)))
            content_parts.append("T*")
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>"
            ),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
            b"<< /Length "
            + str(len(content)).encode("ascii")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, obj in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(index).encode("ascii")
            pdf += obj
            pdf += b"\nendobj\n"

        xref_pos = len(pdf)
        pdf += b"xref\n"
        pdf += "0 {0}\n".format(len(objects) + 1).encode("ascii")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += "<< /Size {0} /Root 1 0 R >>\n".format(
            len(objects) + 1
        ).encode("ascii")
        pdf += b"startxref\n"
        pdf += "{0}\n".format(xref_pos).encode("ascii")
        pdf += b"%%EOF"
        return bytes(pdf)
